function report = runDenseSyntheticMatrix(options)
%RUNDENSESYNTHETICMATRIX Dense Phase A WTA/refinement/SGM truth matrix.
%
% Label spacing is derived independently in every case from measured
% ||dw/dZ|| at 0.25 moving pixels per label. All heights are local ENU metres.
% Traceability: algo/main.tex Secs. 5.1, 10.2, 10.5, and 14.6;
% Eqs. (52)-(56), (126)-(129), and Algorithm 1.

arguments
    options.ImageSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [48, 52]
    options.TileSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [24, 26]
    options.LabelBlockSize (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 4
    options.UseParallel (1, 1) logical = true
    options.NumWorkers (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
    options.ApplySgm (1, 1) logical = true
    options.SgmPenaltyPerMetre (1, 1) double ...
        {mustBeFinite, mustBeNonnegative} = 0.02
    options.SgmMaximumPenalty (1, 1) double ...
        {mustBeFinite, mustBeNonnegative} = 0.2
    options.SgmDirectionCount (1, 1) double ...
        {mustBeMember(options.SgmDirectionCount, [4, 8])} = 4
end

caseNames = ["horizontal-off-grid", "along-track-15deg", ...
    "cross-track-15deg", "step-25m"];
channelNames = ["Zncc", "Census", "NormalizedGradient", ...
    "PointSpin2", "Spin2T0", "Spin2T1", "Spin2T2", ...
    "Spin2T3", "Spin2T4", "HybridZnccSpin2T3"];
caseRows = cell(numel(caseNames), 21);
channelRows = cell(numel(caseNames) * numel(channelNames), 6);
channelRow = 0;

for caseIndex = 1:numel(caseNames)
    renderer = createRenderer(caseNames(caseIndex), options.ImageSize);
    pair = renderer.renderPair;
    geometry = HeightSweepGeometry( ...
        renderer.ReferenceCamera, renderer.MovingCamera);
    levels = 2 ^ renderer.BitDepth - 1;
    curve = HeightCostCurve(geometry, ...
        double(pair.ReferenceImage) ./ levels, ...
        double(pair.MovingImage) ./ levels, ...
        DerivativeSigma=1, IntegrationSigma=1, ...
        ReferenceValid=pair.ReferenceValid, ...
        MovingValid=pair.MovingValid);
    dense = DenseHeightSweep(curve);
    [truthHeight, truthCorrespondence, truthValid] = ...
        truth(renderer, pair);
    [z, spacing, medianObservability] = labels( ...
        geometry, truthHeight, truthValid);

    wta = dense.runTiled(z, Channel="Zncc", ...
        TileSize=options.TileSize, ...
        LabelBlockSize=options.LabelBlockSize, ...
        StoreCostVolumes=options.ApplySgm, UseParallel=options.UseParallel, ...
        NumWorkers=options.NumWorkers);
    refined = HeightSublabelRefiner.refine(z, wta.LabelIndex, ...
        wta.PreviousLabelCost, wta.BestCost, wta.NextLabelCost, ...
        ValidMask=wta.Valid);
    refinedProjection = dense.projectHeightMap( ...
        refined.RefinedHeightMetres, refined.Valid);
    discreteMetrics = metrics(wta.HeightMetres, wta.CorrespondenceXY, ...
        wta.Valid, truthHeight, truthCorrespondence, truthValid);
    refinedMetrics = metrics(refined.RefinedHeightMetres, ...
        refinedProjection.CorrespondenceXY, refinedProjection.Valid, ...
        truthHeight, truthCorrespondence, truthValid);
    if options.ApplySgm
        sgm = HeightSgm.aggregate(wta.CostVolume, z, ...
            PenaltyPerMetre=options.SgmPenaltyPerMetre, ...
            MaximumPenalty=options.SgmMaximumPenalty, ...
            DirectionCount=options.SgmDirectionCount);
        sgmProjection = dense.projectHeightMap(sgm.HeightMetres, sgm.Valid);
        sgmMetrics = metrics(sgm.HeightMetres, ...
            sgmProjection.CorrespondenceXY, sgmProjection.Valid, ...
            truthHeight, truthCorrespondence, truthValid);
        sgmSeconds = sgm.RuntimeSeconds;
    else
        sgmMetrics = emptyMetrics;
        sgmSeconds = NaN;
    end

    caseRows(caseIndex, :) = {caseNames(caseIndex), numel(z), spacing, ...
        medianObservability, nnz(truthValid), ...
        discreteMetrics.Coverage, discreteMetrics.MedianAbsoluteHeight, ...
        discreteMetrics.HeightRmse, discreteMetrics.MedianEpe, ...
        refinedMetrics.Coverage, refinedMetrics.MedianAbsoluteHeight, ...
        refinedMetrics.HeightRmse, refinedMetrics.MedianEpe, ...
        sgmMetrics.Coverage, sgmMetrics.MedianAbsoluteHeight, ...
        sgmMetrics.HeightRmse, sgmMetrics.MedianEpe, sgmSeconds, ...
        wta.Runtime.EvaluationSeconds, ...
        wta.Runtime.MaximumBlockResultBytes, ...
        nnz(pair.ReferenceValid) ./ numel(pair.ReferenceValid)};

    for k = 1:numel(channelNames)
        channelRow = channelRow + 1;
        h = wta.SelectedHeightByChannel.(char(channelNames(k)));
        v = isfinite(h) & truthValid;
        d = abs(h(v) - truthHeight(v));
        channelRows(channelRow, :) = {caseNames(caseIndex), ...
            channelNames(k), nnz(v) ./ max(nnz(truthValid), 1), ...
            median(d), sqrt(mean(d .^ 2)), nnz(v)};
    end
end

caseResults = cell2table(caseRows, VariableNames=[ ...
    "Case", "LabelCount", "LabelSpacingMetres", ...
    "MedianObservabilityPixelsPerMetre", "TruthPixelCount", ...
    "WtaCoverage", "WtaMedianAbsoluteHeightMetres", ...
    "WtaHeightRmseMetres", "WtaMedianEpePixels", ...
    "RefinedCoverage", "RefinedMedianAbsoluteHeightMetres", ...
    "RefinedHeightRmseMetres", "RefinedMedianEpePixels", ...
    "SgmCoverage", "SgmMedianAbsoluteHeightMetres", ...
    "SgmHeightRmseMetres", "SgmMedianEpePixels", ...
    "SgmRuntimeSeconds", ...
    "RuntimeSeconds", "MaximumBlockResultBytes", ...
    "ReferenceImageValidFraction"]);
channelResults = cell2table(channelRows, VariableNames=[ ...
    "Case", "Channel", "Coverage", "MedianAbsoluteHeightMetres", ...
    "HeightRmseMetres", "ValidPixelCount"]);
report = struct( ...
    "CaseResults", caseResults, ...
    "ChannelResults", channelResults, ...
    "TargetMotionPerLabelPixels", 0.25, ...
    "SgmApplied", options.ApplySgm, ...
    "SgmPenaltyPerMetre", options.SgmPenaltyPerMetre, ...
    "SgmMaximumPenalty", options.SgmMaximumPenalty, ...
    "SgmDirectionCount", options.SgmDirectionCount, ...
    "HeightUnits", "metres", ...
    "PixelConvention", "one-based [x,y]=[column,row] centers", ...
    "RawRegularization", "none", ...
    "RegularizationComparison", "physical-height SGM");

fprintf("Dense synthetic WTA/refinement/SGM matrix: %d cases, %d channels\n", ...
    height(caseResults), numel(channelNames));
disp(caseResults(:, ["Case", "LabelSpacingMetres", "WtaCoverage", ...
    "WtaMedianAbsoluteHeightMetres", "WtaMedianEpePixels", ...
    "RefinedCoverage", "RefinedMedianAbsoluteHeightMetres", ...
    "RefinedMedianEpePixels", "SgmCoverage", ...
    "SgmMedianAbsoluteHeightMetres", "SgmMedianEpePixels"]));
end

function renderer = createRenderer(name, imageSize)
switch name
    case "horizontal-off-grid"
        renderer = SyntheticPinholeRenderer(name, imageSize, ...
            Supersample=2, PsfSigmaPixels=0.5, TextureSeed=61, ...
            TrueHeightMetres=1.75);
    case "along-track-15deg"
        renderer = SyntheticPinholeRenderer(name, imageSize, ...
            Supersample=2, PsfSigmaPixels=0.5, TextureSeed=62, ...
            AlongTrackSlopeDegrees=15);
    case "cross-track-15deg"
        renderer = SyntheticPinholeRenderer(name, imageSize, ...
            Supersample=2, PsfSigmaPixels=0.5, TextureSeed=63, ...
            CrossTrackSlopeDegrees=15);
    case "step-25m"
        renderer = SyntheticPinholeRenderer(name, imageSize, ...
            Supersample=2, PsfSigmaPixels=0.5, TextureSeed=64, ...
            SurfaceType="step", StepHeightMetres=25, ...
            StepDirection="along-track");
end
end

function [z, w, valid] = truth(renderer, pair)
[y, x] = ndgrid(1:renderer.ImageSize(1), 1:renderer.ImageSize(2));
p = [x(:), y(:)];
if renderer.SurfaceType == "step"
    [~, z, vr] = PinholeStepOracle.intersect( ...
        renderer.ReferenceCamera, p, renderer.TrueHeightMetres, ...
        renderer.StepHeightMetres, renderer.StepDirectionENU, ...
        renderer.StepPositionMetres);
    [w, vg, inside, visible] = PinholeStepOracle.correspondence( ...
        renderer.ReferenceCamera, renderer.MovingCamera, p, ...
        renderer.TrueHeightMetres, renderer.StepHeightMetres, ...
        renderer.StepDirectionENU, ...
        PositionMetres=renderer.StepPositionMetres);
    valid = vr & vg & inside & visible;
else
    [z, ~, ~, vr] = PinholePlaneOracle.surfaceHeight( ...
        renderer.ReferenceCamera, p, renderer.TrueHeightMetres, ...
        renderer.SurfaceSlopeENU);
    [w, vg, inside] = PinholePlaneOracle.surfaceCorrespondence( ...
        renderer.ReferenceCamera, renderer.MovingCamera, p, ...
        renderer.TrueHeightMetres, renderer.SurfaceSlopeENU);
    valid = vr & vg & inside;
end
valid = valid & pair.ReferenceValid(:);
z = reshape(z, renderer.ImageSize);
w = reshape(w, [renderer.ImageSize, 2]);
valid = reshape(valid, renderer.ImageSize);
end

function [z, spacing, medianObservability] = labels(geometry, truthHeight, valid)
[y, x] = find(valid);
p = [x, y];
h = truthHeight(valid);
[~, kappa, vk] = geometry.heightDerivative(p, h, DeltaHeight=0.5);
medianObservability = median(kappa(vk));
spacing = 0.25 ./ medianObservability;
padding = max(2 .* spacing, 5);
minimum = floor((min(h) - padding) ./ spacing) .* spacing;
maximum = ceil((max(h) + padding) ./ spacing) .* spacing;
% Each colon operand is scalar by the reductions above.
z = minimum:spacing:maximum; %#ok<BDSCI>
end

function result = metrics(h, w, valid, truthHeight, truthW, truthValid)
valid = valid & truthValid & isfinite(h) ...
    & isfinite(w(:, :, 1)) & isfinite(w(:, :, 2));
d = abs(h(valid) - truthHeight(valid));
wx = w(:, :, 1);
wy = w(:, :, 2);
tx = truthW(:, :, 1);
ty = truthW(:, :, 2);
epe = hypot(wx(valid) - tx(valid), wy(valid) - ty(valid));
result = struct( ...
    "Coverage", nnz(valid) ./ max(nnz(truthValid), 1), ...
    "MedianAbsoluteHeight", median(d), ...
    "HeightRmse", sqrt(mean(d .^ 2)), ...
    "MedianEpe", median(epe));
end

function result = emptyMetrics()
result = struct("Coverage", NaN, "MedianAbsoluteHeight", NaN, ...
    "HeightRmse", NaN, "MedianEpe", NaN);
end
